SELECT season
FROM team_performance
WHERE wins = (SELECT MAX(wins) FROM team_performance);

SELECT position, AVG(weight) AS average_weight, COUNT(*) AS player_count
FROM players
GROUP BY position;

SELECT AVG(goals_for) AS average_goals_scored
FROM team_performance
WHERE season = (SELECT MAX(season) FROM team_performance);

SELECT COUNT(player_id) AS active_players
FROM team_players
WHERE status = 'active';

SELECT AVG(professional_years) AS average_professional_years
FROM players
WHERE position = 'Forward' AND professional_years > 10;

SELECT COUNT(*) AS active_player_count
FROM team_players
WHERE status = 'active';

SELECT jersey_number 
FROM players 
ORDER BY jersey_number DESC;

SELECT first_name, last_name, professional_years
FROM players
ORDER BY professional_years DESC;

SELECT DISTINCT most_valuable_player
FROM team_performance
WHERE season = '2022-2023';

SELECT player_id, first_name
FROM players
ORDER BY last_name ASC;
